mapper.select:
SELECT ATCH_FILE_SN, CO_ID, REF_SE_CD, REF_ID, FILE_SE_CD, ORGNL_FILE_NM,
       ENCPT_FILE_NM, FILE_PATH_NM, FILE_SZ, FILE_EXTN_NM, SORT_SEQ,
       USE_YN, RGTR_ID, DATE_FORMAT(REG_DT, '%Y-%m-%d %H:%i') AS REG_DT
FROM atch_file_info
WHERE CO_ID = #{coId}
  AND REF_SE_CD = #{refSeCd}
  AND REF_ID = #{refId}
  AND FILE_SE_CD = #{fileSeCd}
  AND USE_YN = 'Y'
ORDER BY SORT_SEQ ASC, ATCH_FILE_SN DESC

mapper.update:
UPDATE atch_file_info
SET USE_YN = 'N', MDFCN_DT = NOW()
WHERE ATCH_FILE_SN = #{atchFileSn}
  AND CO_ID = #{coId}
  AND REF_SE_CD = 'USER'
  AND REF_ID = #{refId}
  AND USE_YN = 'Y'
